  ('cpa-moex-01323', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於我國公司法上所稱之關係企業，下列敘述何者為正確？', '["分公司與本公司", "公司與他公司之執行業務股東或董事有至少三分之一相同", "具有控制從屬關係或相互投資關係之公司", "彼此有資金往來之公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01324', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '相互投資公司之間彼此知悉有相互投資的事實者，公司法對於其所持有的股份表決權，在行使上有何規 定？', '["對表決權並無限制，由公司自由行使", "限制此等表決權全部不得行使", "不得對抗相互投資公司以外的股東", "不得超過被投資公司已發行有表決權股份的三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01325', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '為使關係企業的財務業務關係可以公開透明，公司法規定在會計年度終了時公司必須編製合併財務報表， 此處之公司是指下列何種公司？', '["所有類型的公司", "所有之股份有限公司", "公開發行股票公司之控制公司", "經主管機關指定的公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01326', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲上市公司於民國100年6月召開之董事會中討論薪資報酬委員會設置事宜，以下那位董事之發言較為 適法？', '["A董事：本公司董事報酬依公司法規定，為股東會所決定，故不需要增設薪資報酬委員會", "B董事：依公司法規定，董事報酬為股東會決議事項，故增設之薪資報酬委員會不得就董事報酬加以 討論", "C董事：薪資報酬委員會所討論之董事薪酬，不僅及於董事之薪資，亦應及於其他對於董事之實質獎 勵事項", "D董事：薪資報酬委員會所討論之經理人薪酬範圍，不應包含經理人所享有之股票選擇權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01327', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列對2007年1月1日才生效之審計委員會相關規定之敘述，何者錯誤？', '["公開發行公司應擇一設置審計委員會或監察人", "審計委員會應由過半獨立董事組成", "審計委員會人數不得少於三人，且至少一人應具備會計或財務專長", "審計委員會之決議，應有審計委員會全體成員二分之一以上之同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01328', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依照證券交易法之規定，私募之有價證券於下列何種情形得再行賣出？', '["並無同種類之有價證券於證券集中交易市場或證券商營業處所買賣者，則持有人即得將該私募有價證 券再行賣出", "自該私募有價證券交付日起已滿一年", "因繼承而取得該私募有價證券者，其得隨時將該私募有價證券再行賣出", "私人間得直接讓受，只要數量不超過該證券一個交易單位，且前後二次讓受行為相隔不少於三個月即可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
